-- rate_library_in.sql  ·  seed for rate_libraries (market=IN)
-- rate_minor = paise (INR x100), ex-GST. Upserts on (market_code,item_code).
on conflict (market_code, item_code) do update
  set rate_minor = excluded.rate_minor,
      item_label = excluded.item_label,
      category   = excluded.category,
      unit       = excluded.unit,
      tier       = excluded.tier,
      region     = excluded.region,
      notes      = excluded.notes;
